window.__QUIZ_DATA__=[{"id":"theory>Marketing>2021>1>a","subject":"Marketing","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ENTREPRENUERSHIP IN MARKETING : FACTORS AFFECTING LOCATION OF A MARKET OUTLET","question":"Mr.Abu, an entrepreneur, wants to establish a public warehousing business.    - State five factors to be considered by Mr.Abu in locating the business","images":[],"marking_scheme":"- Rent, Rates & Taxes   - Workforce availability, labour skills and costs   - Road, Highways and Traffic flow   - Proximity to Airport, Railway stations and Ports   -Markets and local -environment factors   - Building availability and utitlity costs   - Operation cost   - Nearness to distribution","marks":"10","difficulty":"2"},{"id":"theory>Marketing>2021>1>b","subject":"Marketing","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"WAREHOUSING : ACTIVITIES IN THE WAREHOUSING","question":"Mr.Abu, an entrepreneur, wants to establish a public warehousing business.    - Desribe five activities to be carried out by Mr.Abu in the business","images":[],"marking_scheme":"- Receiving: operations that involve the assignment of trucks to ducks, the scheduling and execution of unloading activities     - Storing: Material's movement from unloading area to its designated place in inventory     - Order pick; the process of obtaining the right amount of the right products for a set of customer orders. This is the main and the most labour-intensive activity of warehose     - Shipping: execution of packing and truck's loading after picking, involving also the assignment of trucks to docks     - Delivery: the transit time for transportation from the warehouse to the customer.","marks":"10","difficulty":"2"},{"id":"theory>Marketing>2021>2>a","subject":"Marketing","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ICT IN MARKETING : USES, ETHICS AND ABUSES","question":"State five ways e-marketing can be abused?","images":[],"marking_scheme":"- By chatting with unknown people     - By sending and receiving pornography     - By using bad languages for e-marketing     - By changing the internet address     - By pretending to be someone else     - By changing the voice mode while chatting     - Internet fraud and lack of regulation     - Lack of ethics and hoaxes","marks":"10","difficulty":"2"},{"id":"theory>Marketing>2021>2>b","subject":"Marketing","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ICT IN MARKETING : E-MARKETING - MEANING, IMPORTANCE","question":"Ajax LTD is a marketing company that intends to reach its customer through email.   Explain five important of email to Ajax ltd operation?","images":[],"marking_scheme":"- It will help to reduces the code of advertisement to Ajax LTD     - It will helps the company to track the rate of return on their investment     - It will helps to research on many customers at the same time     - It will enables Ajax LTD to personalize message effectively     - It will helps the company to know the number of their customers effectiviely     - It will build customer relationship even with the past customers     - It is cost effective and permission based","marks":"10","difficulty":"2"},{"id":"theory>Marketing>2021>3>a","subject":"Marketing","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PRODUCTS : PRODUCT DESIGN","question":"Use the diagram to answer question 3(a), 3(b) and 3(c).       - Identify the parts of the product labelled A, B, C and D","images":["data:image/png;base64,"],"marking_scheme":"- Part A is Packaging     - Part B is Brand name     - Part C is Labelling     - Part D is the symbol or logo","marks":"4","difficulty":"3"},{"id":"theory>Marketing>2021>3>b","subject":"Marketing","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"PRODUCTS : MEANING","question":"Use the diagram to answer question 3(a), 3(b) and 3(c).         - State three functions of the part labelled A to the product","images":["data:image/png;base64,"],"marking_scheme":"- It makes advertsing easy     - It facilitates self-service, retailing and mail order business     - It protect the products as they move from producers to sellers and to the final consumers     - It makes for easy handling     - The middlemen are relieved of the burden of having to prepackage the goods","marks":"6","difficulty":"2"},{"id":"theory>Marketing>2021>3>c","subject":"Marketing","year":"2021","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"PRODUCTS : MEANING","question":"Use the diagram to answer question 3(a), 3(b) and 3(c).         - Explain five importance of the part labelled C to the consumer","images":["data:image/png;base64,"],"marking_scheme":"- Information: It informs the customers about the existence of a product.     - Selection: Branding facilitaes self selection and useful for introducing new product     - Pricing: Branding encourages standardised pricing     - Quality of product: Branding is an assurance that the quality of the product will be maintained     - Recognition: It ensure easy recognition of product     - Market segementation: It makes market segementation easier as different brands similar products developed to meet the needs of specific categories of people.","marks":"10","difficulty":"2"},{"id":"theory>Marketing>2021>4>a","subject":"Marketing","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"SALES PROMOTION : MEANING AND FUNCTIONS","question":"Ozayi Ltd is a new manufacturing company producing consumer goods. The company intends to gain market shares by using sales promotion.    - Outline four importance of sales promotion to the company","images":[],"marking_scheme":"- It helps to build the database     - It will help to increase frequency or quantity of purchase     - it can help to cross sell and enforce brand     - it helps to encourage customers to try your products","marks":"8","difficulty":"2"},{"id":"theory>Marketing>2021>4>b","subject":"Marketing","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"SALES PROMOTION : FORMS","question":"Ozayi Ltd is a new manufacturing company producing consumer goods. The company intends to gain market shares by using sales promotion.    - List and explain four sales promotional tools that can be used by the company.","images":[],"marking_scheme":"- Free sample distribution   - Special prices sales   - premium offer   - Competitions   - Trade fairs     -Free sample distribution: Giving out free goods bearing their logo to some of their customers to maintain goodwill and this is good for new products     - Special price sale: This is the process of reducing the price of a product's regular packaging by stating the price reduction in the goods or by selling three products at the price of two.     - Premium offer: Offer a low value of item as a bonus to purchasers of a product, e.g biro or tooth brush in a tooth paste.     -Competition: Customers can be invited to participate in contest, lotteries, raffles in which a fraction of them will win prizes.     - Trade fairs: Displaying samples of the firms product and the literature about the product are given to the enquiring customers.","marks":"12","difficulty":"3"},{"id":"theory>Marketing>2021>5>a","subject":"Marketing","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"MARKETING PLANNING AND RESEARCH : MEANING , PROCESS AND IMPORTANCE OF MARKETING PLANNING","question":"State five importance of marketing planning to an organization","images":[],"marking_scheme":"- Marketing planning provides direction for all organization marketing effort     - Marketing planning help organization to raise finance for capital expenditure     - Marketing planning prevents time wasting on ineffective marketing activities     - It save money by helping to ensure that the marketing budget is spent effectively     - It helps to identify, prerequistes to planned activities     - It helps to generate more clients by communicating effectively","marks":"10","difficulty":"2"},{"id":"theory>Marketing>2021>5>b>i","subject":"Marketing","year":"2021","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MARKET UNIONS AND FACILITATORS : MARKET UNIONS ( MEANING AND TYPES)","question":"Mrs Janet, a dry fish seller, formed an organization with other dry fish sellers for their common interest in a local market.    Identify the organization formed by Mrs Janet with other dry fish sellers.","images":[],"marking_scheme":"The organization formed by Mrs Janet with other dry fish sellers is World Trade Organization(WTO)","marks":"2","difficulty":"1"},{"id":"theory>Marketing>2021>5>b>ii","subject":"Marketing","year":"2021","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"MARKET UNIONS AND FACILITATORS : ROLES OF MARKET UNIONS","question":"Mrs Janet, a dry fish seller, formed an organization with other dry fish sellers for their common interest in a local market.    - State four functions the organization would perform to its members.","images":[],"marking_scheme":"- Overseeing trade agreement     - Reducing trade barriers     - Reducing worldwide tarrifs     - Mediating dispute","marks":"8","difficulty":"2"},{"id":"theory>Marketing>2021>6>a","subject":"Marketing","year":"2021","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"CONSUMER AND ORGANIZATIONAL BEHAVIOUR : MEANING","question":"Abu Company Ltd manufacturers and sells hospital equipment to organizational markets.    - State four features of the markets the company sells its products to","images":[],"marking_scheme":"- Derived demand     - High concentration of production     - Direct channel of distribution     - Few Buyers and large Volume     - Professional buying","marks":"8","difficulty":"2"},{"id":"theory>Marketing>2021>6>b","subject":"Marketing","year":"2021","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"MARKETS : CLASSIFICATION","question":"Abu Company Ltd manufacturers and sells hospital equipment to organizational markets.     - List and explain three types of the market the company sells to.","images":[],"marking_scheme":"- Industrial market: it involves set of all individuals and organizations that acquire goods and services that enter into the production of other products or services that are sold, rented, or supplied to others.     - Reseller market: A market consisting of wholesalers and retailers who buy products for resale purposes. Resellers buy finished goods and resell them to the next level in a given distribution channel.     - Government channel: A government market is a market where the main buyers are federal, state, and local governmental organizations. They purchase goods or services from private businesses.","marks":"12","difficulty":"3"}];